import{_ as a,o as e,c as r,ag as n}from"./chunks/framework.ePeAWSvT.js";const c=JSON.parse('{"title":"RoadMap","description":"","frontmatter":{},"headers":[],"relativePath":"guide/roadmap.md","filePath":"guide/roadmap.md"}'),o={name:"guide/roadmap.md"};function l(s,t,d,i,h,g){return e(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="roadmap" tabindex="-1">RoadMap <a class="header-anchor" href="#roadmap" aria-label="Permalink to &quot;RoadMap&quot;">​</a></h1><p>XnneHangLab 项目的开发路线图与技术债务清理计划。</p><h2 id="工具系统重构-plugin-化-skill-分层" tabindex="-1">工具系统重构：Plugin 化 + Skill 分层 <a class="header-anchor" href="#工具系统重构-plugin-化-skill-分层" aria-label="Permalink to &quot;工具系统重构：Plugin 化 + Skill 分层&quot;">​</a></h2><p><strong>状态：</strong> 设计完成，Phase 1 待执行 <strong>优先级：</strong> 高 <strong>设计文档：</strong> <a href="https://github.com/XnneHangLab/XnneHangLab/issues/262" target="_blank" rel="noreferrer">#262</a> | <strong>讨论记录：</strong> <a href="https://github.com/XnneHangLab/XnneHangLab/issues/260" target="_blank" rel="noreferrer">#260</a></p><p>当前 MCP 工具系统存在结构性问题：内置工具走 MCP HTTP 开销过大、ToolRegistry 手写路由表、tool loop 和具体工具硬耦合。计划重构为 Tool / Skill / Plugin 三层共存架构。</p><p><strong>Phase 路线：</strong></p><table tabindex="0"><thead><tr><th>Phase</th><th>内容</th><th>Issue</th><th>状态</th></tr></thead><tbody><tr><td>Phase 1</td><td>内置工具脱离 MCP，直接 function calling</td><td><a href="https://github.com/XnneHangLab/XnneHangLab/issues/261" target="_blank" rel="noreferrer">#261</a></td><td>待执行</td></tr><tr><td>Phase 2</td><td>Plugin 注册机制 + ToolManager</td><td>待开</td><td>规划中</td></tr><tr><td>Phase 3</td><td>Skill 文件系统 + SkillLoader</td><td>待开</td><td>规划中</td></tr><tr><td>Phase 4</td><td>Hook 机制 + SystemPromptBuilder + Profile 配置</td><td>待开</td><td>规划中</td></tr><tr><td>Phase 5</td><td>memory_bench chat_router 迁移到 src/lab</td><td>待开</td><td>规划中</td></tr><tr><td>Phase 6</td><td>文档同步</td><td>待开</td><td>规划中</td></tr></tbody></table><h2 id="memory-bench-定位调整" tabindex="-1">Memory Bench 定位调整 <a class="header-anchor" href="#memory-bench-定位调整" aria-label="Permalink to &quot;Memory Bench 定位调整&quot;">​</a></h2><p><strong>状态：</strong> 设计完成 <strong>优先级：</strong> 高 <strong>关联：</strong> <a href="https://github.com/XnneHangLab/XnneHangLab/issues/262" target="_blank" rel="noreferrer">#262</a> | <a href="https://github.com/XnneHangLab/XnneHangLab/issues/224" target="_blank" rel="noreferrer">#224</a></p><p>memory_bench 定位为&quot;纯记忆后端（脑子）&quot;，只负责：</p><ol><li>记忆检索 → 注入 → 转发给 LLM</li><li>从 LLM 返回中提取知识 → 写入 mem0 + Neo4j</li><li>保存对话记录</li></ol><p>不包含 tool call 执行、skill 加载等&quot;行动&quot;逻辑。当前 <code>chat_router.py</code> 的 tool loop 将在 Phase 5 迁移到 src/lab 的 Plugin 层。</p><p><strong>待完成：</strong></p><ul><li>[ ] 职责分离重构（透明代理 vs 自治 agent）— <a href="https://github.com/XnneHangLab/XnneHangLab/issues/224" target="_blank" rel="noreferrer">#224</a></li><li>[ ] EMOTION 结构化响应</li><li>[ ] 上下文裁剪策略</li></ul><h2 id="功能开发" tabindex="-1">功能开发 <a class="header-anchor" href="#功能开发" aria-label="Permalink to &quot;功能开发&quot;">​</a></h2><h3 id="独立翻译大模型" tabindex="-1">独立翻译大模型 <a class="header-anchor" href="#独立翻译大模型" aria-label="Permalink to &quot;独立翻译大模型&quot;">​</a></h3><p><strong>状态：</strong> 规划中 <strong>优先级：</strong> 中</p><p>当前翻译依赖外部 DeepLX 服务，计划接入独立的翻译大模型。</p><p><strong>候选模型：</strong></p><ul><li><a href="https://modelscope.cn/models/Tencent-Hunyuan/HY-MT1.5-1.8B" target="_blank" rel="noreferrer">Tencent-Hunyuan/HY-MT1.5-1.8B</a> — 腾讯混元翻译模型</li></ul><p><strong>待完成：</strong></p><ul><li>[ ] 模型集成与推理封装</li><li>[ ] 路由层适配（保持 API 兼容）</li><li>[ ] 性能对比测试（vs DeepLX）</li></ul><h2 id="技术债务" tabindex="-1">技术债务 <a class="header-anchor" href="#技术债务" aria-label="Permalink to &quot;技术债务&quot;">​</a></h2><h3 id="cli-模块定位" tabindex="-1">CLI 模块定位 <a class="header-anchor" href="#cli-模块定位" aria-label="Permalink to &quot;CLI 模块定位&quot;">​</a></h3><p><strong>状态：</strong> 待讨论 <strong>优先级：</strong> 低</p><p><code>cli.py</code> 当前只用于 ASR 命令行工具，是否保留需要评估。</p><p><strong>选项：</strong></p><ol><li>保留并扩展为完整的 CLI 工具集</li><li>移除，ASR 功能通过 API 调用</li><li>拆分到独立的 <code>lab-cli</code> 包</li></ol><hr><p><em>本文档持续更新，反映项目最新规划。</em></p>',30)])])}const u=a(o,[["render",l]]);export{c as __pageData,u as default};
